func wsHandler(w http.ResponseWriter, r *http.Request) {
	conn, err := upgrader.Upgrade(w, r, nil)
	if err != nil {
		fmt.Println("Error upgrading connection:", err)
		return
	}
	defer conn.Close()

	role := getRoleFromHeader(r.Header.Get("Authorization"))
	if role != adminRole {
		sendMessage(conn, "You do not have permission to use admin commands.")
		return
	}

	for {
		messageType, message, err := conn.ReadMessage()
		if err != nil {
			fmt.Println("Error reading message:", err)
			break
		}
		if messageType == websocket.TextMessage {
			handleAdminCommand(conn, string(message), role)
		}
	}
}

func getRoleFromHeader(header string) string {
	parts := strings.Split(header, " ")
	if len(parts) > 1 {
		return parts[1]
	}
	return ""
}

func sendMessage(conn *websocket.Conn, message string) {
	err := conn.WriteMessage(websocket.TextMessage, []byte(message))
	if err != nil {
		fmt.Println("Error sending message:", err)
	}
}

